import Foundation
@testable import GoToBedCore

/// Shared date/calendar utilities for GoToBedTests (app-layer tests).
enum AppLayerTestHelpers {
    /// A deterministic UTC Gregorian calendar for time/weekday assertions.
    static func utcCalendar() -> Calendar {
        var cal = Calendar(identifier: .gregorian)
        cal.timeZone = TimeZone(identifier: "UTC")!
        return cal
    }

    /// Construct an exact Date from components using the given calendar.
    static func date(
        _ year: Int, _ month: Int, _ day: Int,
        _ hour: Int = 0, _ minute: Int = 0, _ second: Int = 0,
        nanosecond: Int = 0,
        calendar: Calendar
    ) -> Date {
        var c = DateComponents()
        c.year = year; c.month = month; c.day = day
        c.hour = hour; c.minute = minute; c.second = second
        c.nanosecond = nanosecond
        return calendar.date(from: c)!
    }
}

import XCTest
@testable import GoToBedKit
@testable import GoToBedCore

/// Unit tests for SchedulerEngine: timer arming, fire callbacks, and stop/rearm
/// lifecycle. SchedulerEngine is @MainActor so the whole test class is isolated
/// to the main actor, which lets timer-firing tests use await to yield the run
/// loop without any extra MainActor.run wrappers.
@MainActor
final class SchedulerEngineTests: XCTestCase {
    private let cal = AppLayerTestHelpers.utcCalendar()

    // MARK: - rearm() state

    func testRearmWithNoSchedulesArmsNoTimer() {
        let engine = SchedulerEngine(store: Store(), calendar: cal)
        engine.rearm()
        XCTAssertNil(engine.nextScheduledFire, "Empty store should leave timer unarmed")
    }

    func testRearmWithEnabledScheduleSetsNextFireDate() {
        // "now" is 09:59; schedule fires at 10:00 — about 60 s in the future.
        let now = AppLayerTestHelpers.date(2025, 1, 6, 9, 59, calendar: cal)
        let store = Store(autosaveEnabled: false)
        store.add(Schedule(hour: 10, minute: 0, weekdays: WeekdayPreset.everyDay, message: "wake"))

        let engine = SchedulerEngine(store: store, calendar: cal, now: { now })
        engine.rearm()

        let fire = engine.nextScheduledFire
        XCTAssertNotNil(fire, "Enabled schedule should arm a timer")
        let h = cal.component(.hour, from: fire!)
        let m = cal.component(.minute, from: fire!)
        XCTAssertEqual(h, 10)
        XCTAssertEqual(m, 0)
    }

    func testRearmWithDisabledScheduleArmsNoTimer() {
        let now = AppLayerTestHelpers.date(2025, 1, 6, 9, 59, calendar: cal)
        let store = Store(autosaveEnabled: false)
        var schedule = Schedule(hour: 10, minute: 0, weekdays: WeekdayPreset.everyDay, message: "x")
        schedule.isEnabled = false
        store.add(schedule)

        let engine = SchedulerEngine(store: store, calendar: cal, now: { now })
        engine.rearm()

        XCTAssertNil(engine.nextScheduledFire, "Disabled schedule must not arm a timer")
    }

    func testRearmPicksSoonestOfMultipleSchedules() {
        let now = AppLayerTestHelpers.date(2025, 1, 6, 7, 0, calendar: cal)
        let store = Store(autosaveEnabled: false)
        // Two enabled schedules: 09:00 and 10:00. Rearm should pick 09:00.
        store.add(Schedule(hour: 9, minute: 0, weekdays: WeekdayPreset.everyDay, message: "first"))
        store.add(Schedule(hour: 10, minute: 0, weekdays: WeekdayPreset.everyDay, message: "second"))

        let engine = SchedulerEngine(store: store, calendar: cal, now: { now })
        engine.rearm()

        let fire = engine.nextScheduledFire
        XCTAssertNotNil(fire)
        XCTAssertEqual(cal.component(.hour, from: fire!), 9)
    }

    // MARK: - stop()

    func testStopClearsArmedFireDate() {
        let now = AppLayerTestHelpers.date(2025, 1, 6, 9, 59, calendar: cal)
        let store = Store(autosaveEnabled: false)
        store.add(Schedule(hour: 10, minute: 0, weekdays: WeekdayPreset.everyDay, message: "x"))

        let engine = SchedulerEngine(store: store, calendar: cal, now: { now })
        engine.rearm()
        XCTAssertNotNil(engine.nextScheduledFire, "Precondition: timer should be armed")

        engine.stop()
        XCTAssertNil(engine.nextScheduledFire, "stop() must clear the armed fire date")
    }

    func testStopIsIdempotent() {
        let engine = SchedulerEngine(store: Store(autosaveEnabled: false), calendar: cal)
        // Two consecutive stops should not crash.
        engine.stop()
        engine.stop()
    }

    // MARK: - onFire callback (real timer, sub-100 ms)

    /// The engine fires onFire when the real Timer elapses.
    ///
    /// Design: "now" is injected as a fixed point 50 ms before the target
    /// hour:minute. The computed timer interval is therefore ~50 ms. After
    /// onFire fires, the schedule is deleted from the store so the subsequent
    /// rearm() finds nothing and does not loop.
    func testOnFireCallbackCalledWhenTimerElapses() async throws {
        // Pick a fire time in the far future so the calendar arithmetic is clean.
        let fireDate = AppLayerTestHelpers.date(2025, 6, 15, 10, 0, calendar: cal)
        // "now" is 50 ms before the target minute → timer interval ≈ 0.05 s.
        let nowDate  = fireDate.addingTimeInterval(-0.05)

        let store = Store(autosaveEnabled: false)
        let s = store.add(Schedule(
            hour: cal.component(.hour, from: fireDate),
            minute: cal.component(.minute, from: fireDate),
            weekdays: WeekdayPreset.everyDay,
            message: "fire-test"
        ))

        var firedSchedule: Schedule?
        let exp = expectation(description: "onFire called")

        let engine = SchedulerEngine(store: store, calendar: cal, now: { nowDate })
        engine.onFire = { [weak store] schedule in
            // Remove the schedule so the post-fire rearm() finds nothing.
            store?.delete(id: schedule.id)
            firedSchedule = schedule
            exp.fulfill()
        }
        engine.start()

        await fulfillment(of: [exp], timeout: 2.0)

        XCTAssertNotNil(firedSchedule)
        XCTAssertEqual(firedSchedule?.message, "fire-test")

        engine.stop()
    }

    /// A schedule that is disabled between arming and firing must be skipped;
    /// onFire must not be called.
    func testFireSkipsScheduleDisabledAfterArming() async throws {
        let fireDate = AppLayerTestHelpers.date(2025, 6, 15, 10, 0, calendar: cal)
        // 300 ms before fire — wide enough to disable the schedule before the timer fires.
        let nowDate  = fireDate.addingTimeInterval(-0.3)

        let store = Store(autosaveEnabled: false)
        let s = store.add(Schedule(
            hour: cal.component(.hour, from: fireDate),
            minute: cal.component(.minute, from: fireDate),
            weekdays: WeekdayPreset.everyDay,
            message: "should-skip"
        ))

        var callbackFired = false
        let engine = SchedulerEngine(store: store, calendar: cal, now: { nowDate })
        engine.onFire = { _ in callbackFired = true }
        engine.start()

        // Disable the schedule immediately after starting (well within the 300 ms window).
        store.setEnabled(false, id: s.id)

        // Wait 700 ms — longer than the timer interval — then assert no callback.
        try await Task.sleep(nanoseconds: 700_000_000)

        XCTAssertFalse(callbackFired, "Disabled schedule must not trigger onFire")

        engine.stop()
    }
}

// MARK: - Store convenience extension (test-only)

private extension Store {
    convenience init(autosaveEnabled: Bool) {
        self.init(
            persistence: AppStatePersistence(directory: .temporaryDirectory),
            autosaveEnabled: autosaveEnabled
        )
    }

    @discardableResult
    func add(_ schedule: Schedule) -> Schedule {
        (self as Store).add(schedule)
    }
}

